const body = $input.first().json.body || $input.first().json;

// Handle Slack URL verification challenge
if (body.type === 'url_verification') {
  return [{ json: { challenge: body.challenge, _skip: true } }];
}

const event = body.event || {};
const text = (event.text || '').trim();
const userId = event.user || '';
const channelId = event.channel || '';
const threadTs = event.thread_ts || event.ts || '';
const msgTs = event.ts || '';
const botId = event.bot_id || '';

// Ignore bot messages (prevent loops)
if (botId || event.subtype === 'bot_message') {
  return [{ json: { _skip: true } }];
}

// Only process messages in #the-council
const COUNCIL_CHANNEL = 'C0AKVJ5PHHR';
if (channelId !== COUNCIL_CHANNEL) {
  return [{ json: { _skip: true } }];
}

// Detect which council members are mentioned (by name or @display name)
const MEMBERS = {
  christian: { name: 'Christian', model: 'christian', role: 'Startup Strategist & Business Operator', emoji: '🎯' },
  kevin:     { name: 'Kevin',     model: 'kevin',     role: 'Systems Architect & Infrastructure Lead', emoji: '🏗️' },
  jason:     { name: 'Jason',     model: 'jason',     role: 'Full-Stack Engineer & Automation Developer', emoji: '⚙️' },
  scaachi:   { name: 'Scaachi',   model: 'scaachi',   role: 'Marketing Lead & Content Strategist', emoji: '✍️' },
  chidi:     { name: 'Chidi',     model: 'chidi',     role: 'Research Analyst & Intelligence Lead', emoji: '🔬' },
};

const textLower = text.toLowerCase();
const explicitlyMentioned = [];
for (const [key, member] of Object.entries(MEMBERS)) {
  if (textLower.includes(key)) {
    explicitlyMentioned.push(key);
  }
}

// Detect if this is a question (ends in ? or starts with question words)
const isQuestion = /\?/.test(text) || /^(what|how|why|when|where|who|can|should|is|are|do|does|will|would|could|think|opinion)/i.test(text.trim());

// Determine which members respond
let respondingMembers = [];

if (explicitlyMentioned.length > 0) {
  // Explicit mention → those members respond
  respondingMembers = explicitlyMentioned;
} else if (isQuestion) {
  // Open question → 1-2 random members respond
  const keys = Object.keys(MEMBERS);
  const shuffled = keys.sort(() => Math.random() - 0.5);
  const count = Math.random() < 0.35 ? 2 : 1; // 35% chance of 2 responses
  respondingMembers = shuffled.slice(0, count);
} else {
  // Statement — 20% chance one member chimes in organically
  if (Math.random() < 0.20) {
    const keys = Object.keys(MEMBERS);
    respondingMembers = [keys[Math.floor(Math.random() * keys.length)]];
  }
}

if (respondingMembers.length === 0) {
  return [{ json: { _skip: true } }];
}

const memberDetails = respondingMembers.map(k => MEMBERS[k]);

return [{ json: {
  text,
  userId,
  channelId,
  threadTs: threadTs || msgTs,
  msgTs,
  isQuestion,
  explicitlyMentioned,
  respondingMembers,
  memberDetails,
  _skip: false,
}}];

const parsed = $('Parse Message').first().json;
const historyData = $input.first().json;
const SLACK_TOKEN = $('Config').first().json.slackToken;

// Helper: HTTPS POST/GET using Node built-in
const httpRequest = (url, opts = {}) => new Promise((resolve, reject) => {
  const { URL } = require('url');
  const https = require('https');
  const http = require('http');
  const parsed_url = new URL(url);
  const client = parsed_url.protocol === 'https:' ? https : http;
  const bodyStr = opts.body || '';
  const headers = { ...(opts.headers || {}) };
  if (bodyStr) headers['Content-Length'] = Buffer.byteLength(bodyStr);
  const req = client.request({
    hostname: parsed_url.hostname,
    port: parsed_url.port,
    path: parsed_url.pathname + parsed_url.search,
    method: opts.method || 'GET',
    headers,
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try { resolve(JSON.parse(data)); } catch { resolve(data); }
    });
  });
  req.on('error', reject);
  if (bodyStr) req.write(bodyStr);
  req.end();
});

// Build initial channel context from recent human messages
const messages = historyData.messages || [];
const contextLines = messages
  .filter(m => !m.bot_id && m.text && m.text.trim())
  .reverse()
  .slice(0, 12)
  .map(m => `<@${m.user || 'user'}>: ${m.text.replace(/<[^>]+>/g, '').trim()}`)
  .join('\n');

const channelContext = contextLines
  ? `Recent conversation in #the-council:\n${contextLines}\n\n`
  : '';

const { channelId, threadTs, userId, text: userText, memberDetails } = parsed;

const postedReplies = [];

for (let idx = 0; idx < memberDetails.length; idx++) {
  const member = memberDetails[idx];

  if (idx > 0) {
    await new Promise(r => setTimeout(r, 4000));

    const threadUrl = `https://slack.com/api/conversations.replies?channel=${channelId}&ts=${threadTs}&limit=20`;
    const threadResp = await httpRequest(threadUrl, {
      method: 'GET',
      headers: { Authorization: `Bearer ${SLACK_TOKEN}` },
    });

    const botMessages = (threadResp.messages || [])
      .filter(m => m.bot_id && m.text)
      .map(m => m.text.replace(/<[^>]+>/g, '').trim())
      .filter(Boolean);

    if (botMessages.length > 0) {
      postedReplies.length = 0;
      postedReplies.push(...botMessages);
    }
  }

  const systemPrompt = `You are ${member.name}, ${member.role} at Biula Tech.

You are in #the-council — a Slack channel where five AI council members advise on company matters. The other members are: Christian 🎯 (Startup Strategist), Kevin 🏗️ (Systems Architect), Jason ⚙️ (Full-Stack Engineer), Scaachi ✍️ (Marketing Lead), Chidi 🔬 (Research Analyst).

Keep replies conversational and concise — 2-4 sentences unless genuine depth is needed. Respond in character, no bullet lists, natural dialogue.`;

  let userPrompt;
  if (postedReplies.length > 0) {
    const priorContext = postedReplies
      .slice(-3)
      .map(r => r.substring(0, 400))
      .join('\n\n---\n\n');
    userPrompt = `${channelContext}<@${userId}> asks: ${userText}\n\n--- Council responses so far ---\n${priorContext}\n\nNow respond as ${member.name}. Build on, challenge, or add nuance to what's been said.`;
  } else {
    userPrompt = `${channelContext}<@${userId}> asks: ${userText}`;
  }

  const ollamaBody = JSON.stringify({
    model: member.model,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt },
    ],
    stream: false,
    options: { temperature: 0.65, num_ctx: 4096 },
  });

  const ollamaResp = await httpRequest('http://host.docker.internal:11434/api/chat', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: ollamaBody,
  });

  const rawReply = ollamaResp.message?.content || ollamaResp.response || '(no response)';
  const formattedReply = `${member.emoji} *${member.name}* — ${member.role}\n\n${rawReply}`;

  postedReplies.push(`${member.name}: ${rawReply}`);

  await httpRequest('https://slack.com/api/chat.postMessage', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${SLACK_TOKEN}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      channel: channelId,
      thread_ts: threadTs,
      text: formattedReply,
      unfurl_links: false,
    }),
  });
}

return [{ json: { done: true, memberCount: memberDetails.length, channelId, threadTs } }];
